content.query:
let MacDevices = DeviceInfo | where OSPlatform == 'macOS' | distinct DeviceId;
let invDevices = DeviceProcessEvents | where TimeGenerated > ago(30d) and DeviceId in (MacDevices) | where FileName in~ ('ollama','openclaw','ollama_llama_server','ollama-runner','mcp-server','codex','codex-cli','claude-code','npx','node','deno') or ProcessCommandLine has_any ('ollama','openclaw','ollama_llama_server','ollama-runner','mcp-server','codex','codex-cli','claude-code','npx','node','deno') | summarize Count = dcount(DeviceId);
let newAI = DeviceProcessEvents | where TimeGenerated > ago(1d) and DeviceId in (MacDevices) | where FileName in~ ('ollama', 'openclaw') or ProcessCommandLine has_any ('ollama', 'openclaw', 'openclaw.mjs') | join kind=leftanti (DeviceProcessEvents | where TimeGenerated between (ago(30d) .. ago(1d)) and DeviceId in (MacDevices) | where FileName in~ ('ollama', 'openclaw') or ProcessCommandLine has_any ('ollama', 'openclaw', 'openclaw.mjs') | distinct DeviceId, FileName, ProcessCommandLine) on DeviceId, FileName, ProcessCommandLine | summarize Count = count();
let localAPI = DeviceNetworkEvents | where TimeGenerated > ago(7d) and DeviceId in (MacDevices) | where ActionType startswith 'Listening' and LocalPort in (11434, 18789) | summarize Count = dcount(DeviceId);
let skillFiles = DeviceFileEvents | where TimeGenerated > ago(7d) and DeviceId in (MacDevices) | where ActionType in ('FileCreated', 'FileModified') | where tolower(FileName) in ('skill.md','skills.md','soul.md','memory.md','agents.md') | summarize Count = count();
let suspSkill = DeviceFileEvents | where TimeGenerated > ago(1d) and DeviceId in (MacDevices) | where ActionType == 'FileCreated' | where tolower(FileName) in ('skill.md', 'skills.md', 'soul.md') | where InitiatingProcessFileName in~ ('curl','wget','python','python3','bash','sh','zsh','nscurl','scp') or isnotempty(FileOriginUrl) | summarize Count = count();
let aiParent = DeviceProcessEvents | where TimeGenerated > ago(30d) and DeviceId in (MacDevices) | where tolower(InitiatingProcessFileName) in ('ollama','openclaw','node','npx','deno') or InitiatingProcessCommandLine has_any ('ollama','openclaw','openclaw.mjs') | where FileName in~ ('sh','bash','zsh','python','python3','curl','wget','scp','osascript','launchctl','security','dscl') | summarize Count = count();
let aiConn = DeviceNetworkEvents | where TimeGenerated > ago(30d) and DeviceId in (MacDevices) | where ActionType in ('ConnectionSuccess', 'ConnectionAttempt') | where InitiatingProcessFileName in~ ('ollama','openclaw','node','npx','deno') or InitiatingProcessCommandLine has_any ('ollama','openclaw') | where RemoteIPType == 'Public' | where RemoteUrl !has 'ollama' and RemoteUrl !has 'openclaw' and RemoteUrl !has 'openai.com' and RemoteUrl !has 'anthropic.com' | summarize Count = count();
let OCpersistence = DeviceFileEvents | where TimeGenerated > ago(1d) and DeviceId in (MacDevices) | where ActionType in ('FileCreated', 'FileModified') | where FolderPath has 'LaunchAgents' and FileName endswith '.plist' | where FileName contains 'openclaw' or InitiatingProcessFileName in~ ('openclaw', 'node') or InitiatingProcessCommandLine has 'openclaw' | summarize Count = count();
union (invDevices      | extend Category = 'Devices with AI Tools (30d)'),(newAI | extend Category = 'New AI Tool Executions (24h)'),(localAPI | extend Category = 'Local AI Servers (7d)'),(skillFiles | extend Category = 'AI Skill Files Modified (7d)'),(suspSkill | extend Category = 'Suspicious Skill File DLs (24h)'),(aiParent | extend Category = 'AI Procs Spawned Sensitive Cmd (30d)'),(aiConn | extend Category = 'External Connections by AI Procs (30d)'),(OCpersistence | extend Category = 'OpenClaw LaunchAgent Plists (24h)') | project Category, Count
